   });
+
+  it('should pass queries to other loader', async () => {
+    const compiler = getCompiler(
+      'other-loader-query.js',
+      {},
+      {
+        module: {
+          rules: [
+            {
+              test: /\.svg$/i,
+              resourceQuery: /color/,
+              enforce: 'pre',
